import { useEffect, useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import {
  addToCart,
  clearCart,
  decreaseCart,
  getTotals,
  removeFromCart,
} from "../slices/cartSlice";
import StripeCheckout from "react-stripe-checkout";
import { Link } from "react-router-dom";
import CheckOut from "./Checkout/CheckOut";
import axios from "axios";
import { toast } from "react-toastify";

import "react-toastify/dist/ReactToastify.css";
const Cart = () => {
  var email = sessionStorage.getItem("UserInfo1");
  console.log(email);
  var name = sessionStorage.getItem("UserInfo");
  console.log(name);
  var userid = sessionStorage.getItem("UserInfoID");
  console.log(userid);

  toast.configure();
  const cart = useSelector((state) => state.cart);
  const dispatch = useDispatch();

  useEffect(() => {
    dispatch(getTotals());
  }, [cart, dispatch]);

  const handleAddToCart = (product) => {
    dispatch(addToCart(product));
  };
  const handleDecreaseCart = (product) => {
    dispatch(decreaseCart(product));
  };
  const handleRemoveFromCart = (product) => {
    dispatch(removeFromCart(product));
  };
  const handleClearCart = () => {
    dispatch(clearCart());
  };
  //product object name,price
  //   async function handleToken(token,address){
  //     const res = await axios.post("http://localhost:1313/checkout",{token,cart})
  //     //take res
  //     console.log(res.status)

  //     if(res.status === 200){
  // toast("payment Success",{type:"success"})
  //     }else{
  // toast("Failure payment is not completed",{type:"error"})
  //     }
  //   }
  const handleToken = async (token) => {
    console.log("handle token");
    axios
      .post("http://localhost:1313/checkout", {
        token,
        cart,
        userid,
      })
      .then((res) => {
        console.log(res.data);
        toast("payment Success", { type: "success" });
        // localStorage.removeItem("cartItems");
      })
      .catch((err) => {
        toast("Failure payment is not completed", { type: "error" });
        console.log(err);
      });
  };

  return (
    <div className="cart-container">
      <h2>Shopping Cart</h2>
      {cart.cartItems.length === 0 ? (
        <div className="cart-empty">
          <p>Your cart is currently empty</p>
          <div className="start-shopping">
            <Link to="/home">
              <svg
                xmlns="http://www.w3.org/2000/svg"
                width="20"
                height="20"
                fill="currentColor"
                className="bi bi-arrow-left"
                viewBox="0 0 16 16"
              >
                <path
                  fillRule="evenodd"
                  d="M15 8a.5.5 0 0 0-.5-.5H2.707l3.147-3.146a.5.5 0 1 0-.708-.708l-4 4a.5.5 0 0 0 0 .708l4 4a.5.5 0 0 0 .708-.708L2.707 8.5H14.5A.5.5 0 0 0 15 8z"
                />
              </svg>
              <span>Start Shopping</span>
            </Link>
          </div>
        </div>
      ) : (
        <div>
          <div className="titles">
            <h3 className="product-title">Product</h3>
            <h3 className="price">Price</h3>
            <h3 className="quantity">Quantity</h3>
            <h3 className="total">Total</h3>
          </div>
          <div className="cart-items">
            {cart.cartItems &&
              cart.cartItems.map((cartItem) => (
                <div className="cart-item" key={cartItem.id}>
                  <div className="cart-product">
                    <img
                      src={"http://localhost:1313/images/" + cartItem.image}
                      alt={cartItem.name}
                    />
                    <div>
                      <h3>{cartItem.name}</h3>
                      <p>{cartItem.pro_desc}</p>
                      <button onClick={() => handleRemoveFromCart(cartItem)}>
                        Remove
                      </button>
                    </div>
                  </div>
                  <div className="cart-product-price">₹{cartItem.price}</div>
                  <div className="cart-product-quantity">
                    <button onClick={() => handleDecreaseCart(cartItem)}>
                      -
                    </button>
                    <div className="count">{cartItem.cartQuantity}</div>
                    <button onClick={() => handleAddToCart(cartItem)}>+</button>
                  </div>
                  <div className="cart-product-total-price">
                    ₹{cartItem.price * cartItem.cartQuantity}
                  </div>
                </div>
              ))}
          </div>
          <div className="cart-summary">
            <button className="clear-btn" onClick={() => handleClearCart()}>
              Clear Cart
            </button>
            <div className="cart-checkout">
              <div className="subtotal">
                <span>Subtotal</span>
                <span className="amount">₹{cart.cartTotalAmount}</span>
              </div>
              <p>Taxes and shipping calculated at checkout</p>

              <button>
                <StripeCheckout
                  className="flex w-full"
                  stripeKey="pk_test_uNtUbsKyB6tXqfxx2l78iuPu00Upvk5XUJ"
                  token={handleToken}
                  amount={cart.cartTotalAmount * 100}
                  name={name}
                  email={email}
                  currency="INR"

                  // billingAddress
                  // shippingAddress
                />
              </button>
              <div className="continue-shopping">
                <Link to="/home">
                  <svg
                    xmlns="http://www.w3.org/2000/svg"
                    width="20"
                    height="20"
                    fill="currentColor"
                    className="bi bi-arrow-left"
                    viewBox="0 0 16 16"
                  >
                    <path
                      fillRule="evenodd"
                      d="M15 8a.5.5 0 0 0-.5-.5H2.707l3.147-3.146a.5.5 0 1 0-.708-.708l-4 4a.5.5 0 0 0 0 .708l4 4a.5.5 0 0 0 .708-.708L2.707 8.5H14.5A.5.5 0 0 0 15 8z"
                    />
                  </svg>
                  <span>Continue Shopping</span>
                </Link>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Cart;
